package com.company.supervision.api;import com.company.supervision.application.messaging.MessageService;import com.company.supervision.entity.dto.ApiResult;import org.springframework.web.bind.annotation.*;import java.util.*;@RestController @RequestMapping("/messages") public class MessageController{private final MessageService s;public MessageController(MessageService s){this.s=s;}@PostMapping("/preview")public ApiResult<?>preview(@RequestBody Map<String,Object>r){return ApiResult.ok(s.preview(r));}@PostMapping("/test-send")public ApiResult<?>test(@RequestBody Map<String,Object>r){return ApiResult.ok(s.test(r));}@GetMapping("/deliveries")public ApiResult<?>list(){return ApiResult.ok(s.list());}}